INSERT INTO `mybb_sg_sg_virtudes` (`virtud_id`, `nombre`, `puntos`, `exclusivo`, `descripcion`) VALUES
('DINYIN', 'Incompatibilidad Yin', -3, 0, 'El ninja no puede aprender técnicas Yin bajo ninguna circunstancia. (No aplica a técnicas de clan).'),
('DINYAN', 'Incompatibilidad Yang', -3, 0, 'El ninja no puede aprender técnicas Yang bajo ninguna circunstancia. (No aplica a técnicas de clan).'),
('DINELE', 'Incompatibilidad Elemental', -3, 0, 'El ninja no puede obtener un elemento básico ni avanzado. (Incompatible con clanes que requieran de algún o algunos elementos específicos).'),
('DAMBRA', 'Amputación de Brazo', -5, 0, 'El ninja ha perdido uno de sus brazos, impidiéndole realizar sellos manuales en circunstancias normales o portar armas a dos manos. Este defecto debe rolearse de forma coherente.\n\n-20 puntos a su Destreza.'),
('DAMPIE', 'Amputación de Pierna', -4, 0, 'El ninja ha perdido una de sus piernas y con ello, una gran capacidad en su movilidad. Este defecto debe rolearse de forma coherente.\n\n-5 puntos a su Velocidad.'),
('DSORDE', 'Sordera', -3, 0, 'El ninja carece del sentido auditivo. Todas las ofensivas en su contra que no puedan ver directamente se considerarán como sigilosas.'),
('DMFLUJ', 'Mal Flujo', -2, 0, 'El flujo de chakra del ninja es impuro, provocando un mayor desgaste al usar chakra. (Incompatible con Buen Flujo).\n\n20% extra de gasto de chakra a todas las técnicas.'),
('DCLLEE', 'Clan Lee', -5, 0, 'El ninja es incapaz de utilizar Ninjutsu y Genjutsu y cualquier técnica que se clasifique como tal y no sea Taijutsu por el resto de su historia.\n\nIncapacidad de usar Ninjutsu y Genjutsu.'),
('DFEURA', 'Feúra', -1, 0, 'El ninja no es agraciado físicamente, cosa que no pasa desapercibida. Es posible que esto le dificulte su capacidad de crear vínculos o encontrar oportunidades en momentos clave. (Incompatible con Atractivo).'),
('DVICIO', 'Vicio', -1, 0, 'El ninja tiene una inclinación constante hacia una sustancia o hábito del que le resulta difícil desprenderse. Un ancla pequeña que no le detiene pero le impide avanzar con total libertad. (El vicio deberá satisfacerse cada 5 post).\n\nEl atributo más alto del ninja se reduce en 10 puntos mientras no satisfaga su vicio. De ser iguales, se reduce el que el usuario elija.'),
('DADICC', 'Adicción', -3, 0, 'El ninja tiene una inclinación muy constante a una sustancia o hábito del que le resulta casi imposible desprenderse. Teniendo un grave síndrome de abstinencia de no satisfacer su adicción. (La adicción deberá satisfacerse cada 5 post).\n\nTodos los atributos del ninja se reducen en 10 puntos acumulativos por cada turno que no satisfaga su adicción.'),
('DIMPOP', 'Impopularidad', -2, 0, 'El ninja mantiene una reducción del -10% en su Bingo. (Incompatible con Fama).'),
('DCOMP1', 'Comprador Impulsivo I', -1, 0, 'El ninja empieza con -1000 Ryos y además todos los objetos que compre costarán un 10% más. (Incompatible con Comprador Impulsivo II y III. Incompatible con Adinerado I, II y III).'),
('DCOMP2', 'Comprador Impulsivo II', -2, 0, 'El ninja empieza con -2000 Ryos y además todos los objetos que compre costarán un 20% más. (Incompatible con Comprador Impulsivo I y III. Incompatible con Adinerado I, II y III).'),
('DCOMP3', 'Comprador Impulsivo III', -3, 0, 'El ninja empieza con -3000 Ryos y además todos los objetos que compre costarán un 30% más. (Incompatible con Comprador Impulsivo I y II. Incompatible con Adinerado I, II y III).'),
('DVACIL', 'Voluntad Vacilante', -4, 0, 'El miedo a morir es capaz de doblegar la voluntad del ninja. Cuando los PV del ninja estén por debajo del 20% total, todos sus atributos se reducirán en 20 puntos y solo podrá ejecutar acciones defensivas o evasivas. (Incompatible con Instinto de Supervivencia).'),
('DULACT', 'Último Acto', -1, 0, 'El ninja siempre tendrá una sanción pasiva agregada del 20% sobre su Bingo.'),
('DFOBI1', 'Fobia I', -1, 0, 'El ninja tiene un temor intenso, irracional y desproporcionado a algo no tan común a elección dentro del mundo. No podrá cambiar de miedo en el transcurso de la historia. Esta fobia debe ser algo relativamente fácil de encontrar y no en una posibilidad ínfima ni excesivamente exclusiva.\n\nTodos los atributos del ninja se reducen en 10 puntos mientras se encuentre en presencia de su miedo. Los stats se restauran al siguiente turno de haberse alejado.'),
('DFOBI2', 'Fobia II', -2, 0, 'El ninja tiene un temor intenso, irracional y desproporcionado a algo común a elección dentro del mundo. No podrá cambiar de miedo en el transcurso de la historia. Esta fobia debe ser algo relativamente fácil de encontrar y no en una posibilidad ínfima ni excesivamente exclusiva.\n\nTodos los atributos del ninja se reducen en 10 puntos mientras se encuentre en presencia de su miedo. Los stats se restauran al siguiente turno de haberse alejado.'),
('DFOBI3', 'Fobia III', -3, 0, 'El ninja tiene un temor intenso, irracional y desproporcionado a algo muy común a elección dentro del mundo. No podrá cambiar de miedo en el transcurso de la historia. Esta fobia debe ser algo relativamente fácil de encontrar y no en una posibilidad ínfima ni excesivamente exclusiva.\n\nTodos los atributos del ninja se reducen en 10 puntos mientras se encuentre en presencia de su miedo. Los stats se restauran al siguiente turno de haberse alejado.'),
('DALER1', 'Alergia I', -2, 0, 'El ninja tiene una reacción exagerada del sistema inmunitario ante sustancias o compuestos inofensivos poco comunes a elección. No podrá cambiar de alergia por el resto de la historia.\n\nLa velocidad del ninja se reduce a la mitad y pierde la capacidad de saltar mientras se encuentre en presencia de su alergia. Las desventajas se eliminan al siguiente turno después de alejarse.'),
('DALER2', 'Alergia II', -3, 0, 'El ninja tiene una reacción exagerada del sistema inmunitario ante sustancias o compuestos inofensivos comunes a elección. No podrá cambiar de alergia por el resto de la historia.\n\nLa velocidad del ninja se reduce a la mitad y pierde la capacidad de saltar mientras se encuentre en presencia de su alergia. Las desventajas se eliminan al siguiente turno después de alejarse.'),
('DALER3', 'Alergia III', -4, 0, 'El ninja tiene una reacción exagerada del sistema inmunitario ante sustancias o compuestos inofensivos muy comunes a elección. No podrá cambiar de alergia por el resto de la historia.\n\nLa velocidad del ninja se reduce a la mitad y pierde la capacidad de saltar mientras se encuentre en presencia de su alergia. Las desventajas se eliminan al siguiente turno después de alejarse.'),
('DMUDEZ', 'Mudez', -4, 0, 'El ninja fue privado de la capacidad de hablar por una discapacidad en las cuerdas vocales. Su mundo se expresa a través de gestos, miradas y acciones. Esta condición no solo dificulta la transmisión de ideas complejas, sino que puede generar malentendidos o aislarle en momentos clave.'),
('DSILEN', 'Voto de Silencio', -2, 0, 'Por decisión propia, el ninja ha renunciado al uso de la palabra, adoptando el silencio como una forma de vida. Sus pensamientos permanecen resguardados, y su comunicación se limita a gestos, miradas o acciones cuidadosamente medidas. (El ninja podrá romper su voto de silencio una sola vez por tema).'),
('DCEGUE', 'Ceguera', -5, 0, 'El ninja ha perdido por completo el sentido de la visión. Ya sea que sus ojos estén ciegos o directamente no los tenga.\n\nTodas las ofensivas que vayan dirigidas en su contra se considerarán como sigilosas.'),
('DTUERT', 'Tuerto', -3, 0, 'El ninja carece de uno de sus ojos a elección, dificultando su posibilidad de defenderse de ataques que vengan desde su punto ciego. (Incompatible con Ceguera).\n\nTodas las ofensivas que vayan dirigidas en su contra contarán con +1 nivel a la hora de esquivar.'),
('DLEALT', 'Lealtad', -2, 0, 'El ninja es sumamente leal a su aldea, por lo que no podrá renegar de ella jamás salvo por una causa lógica apoyada por el Staff.'),
('DPOSC1', 'Pasado Oscuro I', -1, 0, 'El ninja carga con el peso de formar parte de una familia marcada por el descontento y el desprestigio. Su nombre, ligado a una familia de reputación cuestionable, dentro o fuera de un clan, podría despertar recelo antes de que pueda demostrar quién es en realidad, lo que dificulta la creación de vínculos. (Incompatible con Pasado Influyente I y II y Pasado Oscuro II).\n\nCreación de un NPC propio de máximo nivel 10 y rango Chunin que sea familiar del personaje.'),
('DPOSC2', 'Pasado Oscuro II', -3, 0, 'El ninja carga con el peso de formar parte de una familia marcada por el descontento y el desprestigio. Su nombre, ligado a una familia de reputación cuestionable, dentro o fuera de un clan, podría despertar recelo antes de que pueda demostrar quién es en realidad, lo que dificulta la creación de vínculos. (Incompatible con Pasado Influyente I y II y Pasado Oscuro I).\n\nCreación de un NPC propio de máximo nivel 15 y rango Anbu o Tokubetsu Jōnin que sea familiar del personaje.'),
('DSCALI', 'Sangre Caliente', -2, 0, 'El ninja no sabe ignorar una provocación. Ante el más mínimo insulto, su respuesta surge casi por reflejo, como si el silencio fuera una opción inexistente. Esta incapacidad para dejar pasar las ofensas le arrastra con frecuencia a discusiones innecesarias, tensando situaciones que podrían haberse evitado.'),
('DSINCE', 'Sinceridad', -2, 0, 'El ninja es incapaz de mentir, ya sea filosofía propia, valores, o lo que sea. Siempre dirá la verdad independientemente de a quien se dirija lo que puede poner en riesgo información delicada.'),
('DCSELE', 'Código Selectivo', -4, 0, 'El ninja es incapaz de agredir hombres o mujeres (a elección) por el resto de su historia. Deberá especificarse en la ficha del personaje.'),
('DIRRIT', 'Irritante', -2, 0, 'Algo en el ninja puede generar rechazo en aquellos con los que interactúa. Puede ser una actitud, una forma de expresarse, algo en su físico, etcétera. (Se debe especificar en la ficha del personaje).'),
('DDESHO', 'Deshonor', -3, 0, 'El ninja comienza siendo un renegado de alguna aldea lo que le quita la posibilidad de acceder a los beneficios que solo gozarían quienes mantuvieron su lealtad a su aldea. Esto también le impide unirse posteriormente a una aldea por el resto de su historia salvo por una causa lógica apoyada por el Staff. (Incompatible con Lealtad).'),
('DSOLUN', 'Solo Uno', -1, 0, 'El usuario no podrá tener más de un personaje. Quitando la posibilidad de obtener multicuentas.'),
('DDESPI', 'Despistado', -3, 0, 'El ninja carece de una buena memoria. Podría olvidar nombres, lugares, direcciones y en otros casos, información importante.\n\nCada 5 post, el usuario lanza un dado 1d20 donde 1-10 olvidará algo importante y 11-20 olvidará algo de baja importancia. A discreción del narrador. De pasar en un tema social, esto queda a elección del usuario, pero debe ser coherente.'),
('DNELUD', 'Nunca Eludir', -3, 0, 'El ninja es incapaz de acceder al Modo Seguro en cualquier tema donde este participe.'),
('DPACIF', 'Pacifista', -3, 0, 'El ninja tiende a ser extremadamente diplomático y siempre busca solucionar los problemas por medio del diálogo, accediendo al combate en última instancia. Adicionalmente, el ninja no podrá matar a nadie salvo por un accidente.'),
('DPROSO', 'Prosopagnosia', -2, 0, 'El ninja es incapaz de distinguir rostros familiares, incluyendo el propio, valiéndose de otros factores como el color de cabello, forma de caminar, voz, etcétera, para distinguir a las personas. (Incompatible con Ceguera).'),
('DIGNOR', 'Ignorante', -2, 0, 'El ninja sabe poco o nada del mundo que lo rodea. No sabe de clanes, aldeas o hasta los conflictos de su propio entorno. De la misma forma, toda información importante que obtenga el ninja no tendrá la misma utilidad (a discreción de moderación).'),
('DHISTR', 'Trastorno Histriónico', -2, 0, 'El ninja tiene la necesidad compulsiva de ser el centro de atención, a menudo actuando de manera provocativa o seductora. Un comportamiento autoconsciente y superficialmente afectuoso, actuando como un actor.'),
('DTDAH', 'TDAH', -2, 0, 'El ninja tiene una inquietud física constante, incapacidad para quedarse quieto, o una inquietud mental. Actúa sin pensar, interrumpe conversaciones y tiene dificultad para esperar turnos.'),
('DSINHE', 'Sin Herencia', -5, 0, 'Una vez el ninja que tenga este defecto muera, sin importar la causa o razón de muerte, el usuario no podrá hacer uso del tutorial de muerte para su próximo personaje, por lo que este último no heredará nada.'),
('DSMUER', 'Sentencia de Muerte', -5, 0, 'El corazón del ninja no funciona como debería y en cualquier momento podría detenerse de golpe.\n\nAl comienzo de cada mes Off-Rol, el usuario deberá solicitar la tirada de un dado 1D20 (la tirada la hará un Mod o Staff) y de sacar 1, su personaje morirá irremediablemente.'),
('DTRAIC', 'Traicionable', -3, 0, 'El ninja es fácilmente despreciado. Existe la posibilidad de que algún NPC vea en él a alguien desechable.\n\nEn misiones y eventos, al comienzo del tema, el usuario tirará un dado 1D20, de salir 1, algún NPC cercano lo traicionará. A discreción del narrador.'),
('DVERBO', 'Verborrea Shinobi', -1, 0, 'Al ninja le resulta imposible ejecutar un jutsu sin anunciarlo en voz alta. Ya sea por costumbre arraigada, impulso incontrolable o una extraña manía, cada técnica que emplea va acompañada de su nombre proclamado con claridad. Esta peculiaridad dificulta el sigilo y puede delatar sus intenciones en momentos críticos. (Incompatible con Mudez y Voto de Silencio).'),
('DVENGA', 'Venganza', -3, 0, 'El ninja tiene rencor hacia algún clan, aldea o facción en específico haciéndolo reaccionar de forma agresiva contra ellos, sabotearlos o sencillamente no cooperar. (Se debe especificar en los extras del personaje).'),
('DSDILU', 'Sangre Diluida', -3, 0, 'Todos los sangrados del ninja sufrirán un aumento de un nivel de intensidad. (Incompatible con Sangre Resistente).'),
('DPSICO', 'Psicopatía', -1, 0, 'El ninja resulta ser una persona que se caracteriza por una profunda falta de empatía, ausencia de remordimientos y un comportamiento manipulador. Aunque superficialmente puede parecer encantador y normal, carece de vínculos afectivos reales y utiliza a los demás para beneficio propio.'),
('DESQUI', 'Esquizofrenia', -2, 0, 'El ninja puede perder el contacto con la realidad, presentando dificultades para diferenciar entre experiencias reales e irreales, pensar con lógica y mantener emociones normales. Lo que dificulta su socialización o estabilidad con otros.\n\nEste defecto debe rolearse de forma coherente.');
